// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

const OPERATION_NAME = 'dynatrace update notebook';
const METHOD = 'PUT';
const ENDPOINT_TEMPLATE = '/platform/document/v1/documents/{documentId}';

function expandPath(template, params) {
  return template.replace(/\{([^}]+)\}/g, (_, key) => encodeURIComponent(params[key] ?? ''));
}

async function parseResponse(response) {
  const text = await response.text();
  if (!text) {
    return { status: response.status, statusText: response.statusText };
  }

  try {
    return JSON.parse(text);
  } catch {
    return { status: response.status, statusText: response.statusText, text };
  }
}

export default async function (input) {
  const ex = await execution();
  console.log('Running', OPERATION_NAME, 'triggered by', ex.trigger);

  let url = expandPath(ENDPOINT_TEMPLATE, input);
  if (input.queryString && input.queryString.trim()) {
    url += (url.includes('?') ? '&' : '?') + input.queryString.trim();
  }

  const request = {
    method: METHOD,
    headers: {
      'Content-Type': 'application/json'
    }
  };

  if (['POST', 'PUT', 'PATCH'].includes(METHOD)) {
    let body = {};

    if (ENDPOINT_TEMPLATE === '/platform/storage/query/v1/query:execute') {
      body = {
        query: input.dqlQuery && input.dqlQuery.trim() ? input.dqlQuery : 'fetch events | limit 20'
      };
    } else if (input.payloadJson && input.payloadJson.trim()) {
      body = JSON.parse(input.payloadJson);
    }

    request.body = JSON.stringify(body);
  }

  const response = await fetch(url, request);
  const result = await parseResponse(response);

  if (!response.ok) {
    throw new Error('Dynatrace API request failed (' + response.status + ') for ' + METHOD + ' ' + url + ': ' + JSON.stringify(result));
  }

  return {
    operation: OPERATION_NAME,
    method: METHOD,
    endpoint: url,
    triggeredBy: ex.trigger,
    result
  };
}
